SELECT s.fulfillment_channel, SUM(s.product_gms) AS total_sales, (SUM(c.conceded_units) * 100.0) / NULLIF(SUM(s.shipped_units), 0) AS return_rate_pct FROM shipped_raw s LEFT JOIN concession_raw c ON c.asin = s.asin AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE s.fulfillment_channel IS NOT NULL GROUP BY s.fulfillment_channel ORDER BY total_sales DESC;